import React, { useState, useCallback } from "react";
import axios from "axios";
import "./App.css";
import IndividualAnalysis from "./IndividualAnalysis";
import BatchAnalysis from "./BatchAnalysis";

const API_BASE = "http://localhost:5000/api";

const DEFAULT_CUSTOMER_DATA = {
  Tenure: 5.0,
  OrderCount: 5.0,
  CashbackAmount: 12000.0,
  DaySinceLastOrder: 7.0,
  HourSpendOnApp: 30.0,
  OrderAmountHikeFromlastYear: 15.0,
  CouponUsed: 1,
  NumberOfDeviceRegistered: 3,
  Complain: 0,
  SatisfactionScore: 3,
  WarehouseToHome: 10.0,
  NumberOfAddress: 4,
  CityTier: 1,
  PreferredLoginDevice: "Mobile Phone",
  PreferredPaymentMode: "Credit Card",
  PreferedOrderCat: "Laptop & Accessory",
  Gender: "Male",
  MaritalStatus: "Married",
};

function App() {
  const [mode, setMode] = useState("individual");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [results, setResults] = useState(null);
  const [batchResults, setBatchResults] = useState(null);
  const [batchFile, setBatchFile] = useState(null);
  const [customerData, setCustomerData] = useState(DEFAULT_CUSTOMER_DATA);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const handleModeChange = useCallback((newMode) => {
    setMode(newMode);
    setResults(null);
    setBatchResults(null);
    setError(null);
    setSidebarOpen(false);
  }, []);

  const handleResetForm = useCallback(() => {
    setCustomerData(DEFAULT_CUSTOMER_DATA);
    setResults(null);
    setError(null);
  }, []);

  const handleIndividualAnalyze = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await axios.post(`${API_BASE}/individual`, customerData);
      const enhancedResults = {
        ...res.data,
        timestamp: new Date().toISOString(),
        id: Date.now(),
      };
      setResults(enhancedResults);
    } catch (err) {
      const errorMessage = err.response?.data?.message || "Failed to analyze customer data. Please try again.";
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const handleBatchAnalyze = async () => {
    if (!batchFile) {
      setError("Please select a CSV file to begin analysis");
      return;
    }

    if (!batchFile.name.toLowerCase().endsWith('.csv')) {
      setError("Please upload a valid CSV file");
      return;
    }

    setLoading(true);
    setError(null);
    const formData = new FormData();
    formData.append("file", batchFile);

    try {
      const res = await axios.post(`${API_BASE}/batch`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
        timeout: 30000,
      });

      const enhancedResults = {
        ...res.data,
        timestamp: new Date().toISOString(),
        fileName: batchFile.name,
        id: Date.now(),
      };

      setBatchResults(enhancedResults);
    } catch (err) {
      const errorMessage = err.response?.data?.message || "Failed to process batch file. Please check the file format and try again.";
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const exportResults = () => {
    if (!results && !batchResults) return;

    const data = mode === "individual" 
      ? { 
          type: "individual_analysis",
          timestamp: new Date().toISOString(),
          customerData, 
          analysis: results 
        }
      : { 
          type: "batch_analysis",
          timestamp: new Date().toISOString(),
          batchAnalysis: batchResults 
        };

    const blob = new Blob([JSON.stringify(data, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `churn-analysis-${mode}-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="app-wrapper">
      {/* Navigation Sidebar */}
      <div className={`sidebar ${sidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h3>Navigation</h3>
          <button className="close-sidebar" onClick={() => setSidebarOpen(false)}>×</button>
        </div>
        <nav className="sidebar-nav">
          <button 
            className={`nav-item ${mode === "individual" ? "active" : ""}`}
            onClick={() => handleModeChange("individual")}
          >
            <span className="nav-icon">👤</span>
            Individual Analysis
          </button>
          <button 
            className={`nav-item ${mode === "batch" ? "active" : ""}`}
            onClick={() => handleModeChange("batch")}
          >
            <span className="nav-icon">📊</span>
            Batch Analysis
          </button>
          <div className="nav-divider"></div>
          <button className="nav-item">
            <span className="nav-icon">📈</span>
            Analytics Dashboard
          </button>
          <button className="nav-item">
            <span className="nav-icon">⚙️</span>
            Settings
          </button>
        </nav>
      </div>

      {/* Main Content */}
      <div className="main-content">
        <header className="top-header">
          <div className="header-content">
            <button 
              className="menu-toggle"
              onClick={() => setSidebarOpen(!sidebarOpen)}
            >
              ☰
            </button>
            <div className="header-title">
              <h1 className="project-title">
                <span className="title-gradient">Customer Churn Intelligence</span>
              </h1>
              <p className="tagline">AI-Powered Customer Retention Platform</p>
            </div>
            <div className="header-stats">
              <div className="stat">
                <span className="stat-value">99.2%</span>
                <span className="stat-label">Accuracy</span>
              </div>
            </div>
          </div>

          <div className="mode-indicator">
            <div className="mode-tabs">
              <button
                className={`mode-tab ${mode === "individual" ? "active" : ""}`}
                onClick={() => handleModeChange("individual")}
              >
                <span className="tab-icon">👤</span>
                Individual Analysis
                <span className="tab-badge">Real-time</span>
              </button>
              <button
                className={`mode-tab ${mode === "batch" ? "active" : ""}`}
                onClick={() => handleModeChange("batch")}
              >
                <span className="tab-icon">📊</span>
                Batch Processing
                <span className="tab-badge">Bulk</span>
              </button>
            </div>
          </div>
        </header>

        <main className="dashboard">
          {/* Error Display */}
          {error && (
            <div className="error-banner">
              <div className="error-content">
                <span className="error-icon">⚠️</span>
                <div className="error-text">
                  <strong>Analysis Error</strong>
                  <p>{error}</p>
                </div>
              </div>
              <button onClick={() => setError(null)} className="close-error">×</button>
            </div>
          )}

          {/* Loading Overlay */}
          {loading && (
            <div className="loading-overlay">
              <div className="loading-content">
                <div className="loading-spinner"></div>
                <div className="loading-text">
                  <h3>Processing Analysis</h3>
                  <p>{mode === "individual" ? "Analyzing customer data..." : "Processing batch file..."}</p>
                </div>
                <div className="loading-progress">
                  <div className="progress-bar">
                    <div className="progress-fill"></div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Analysis Content */}
          <div className="analysis-content">
            {mode === "individual" ? (
              <IndividualAnalysis
                customerData={customerData}
                onInputChange={setCustomerData}
                onAnalyze={handleIndividualAnalyze}
                onReset={handleResetForm}
                loading={loading}
                results={results}
              />
            ) : (
              <BatchAnalysis
                onFileChange={(e) => {
                  setBatchFile(e.target.files[0]);
                  setError(null);
                }}
                onAnalyze={handleBatchAnalyze}
                loading={loading}
                results={batchResults}
                selectedFile={batchFile}
              />
            )}
          </div>

          {/* Export Section */}
          {(results || batchResults) && (
            <div className="export-section">
              <div className="export-card">
                <div className="export-header">
                  <h3>📤 Analysis Complete</h3>
                  <p>Your results are ready for export</p>
                </div>
                <div className="export-actions">
                  <button onClick={exportResults} className="export-btn primary">
                    <span className="btn-icon">💾</span>
                    Export JSON Report
                  </button>
                  <button className="export-btn secondary">
                    <span className="btn-icon">📧</span>
                    Email Results
                  </button>
                  <button className="export-btn secondary">
                    <span className="btn-icon">🖨️</span>
                    Print Report
                  </button>
                </div>
              </div>
            </div>
          )}
        </main>

        {/* Footer */}
        <footer className="app-footer">
          <div className="footer-content">
            <div className="footer-info">
              <span className="footer-logo">CCI</span>
              <span>Customer Churn Intelligence v2.0</span>
            </div>
            <div className="footer-links">
              <span>© 2024 AI Analytics Platform</span>
              <div className="footer-badges">
                <span className="badge">Secure</span>
                <span className="badge">AI-Powered</span>
                <span className="badge">Real-time</span>
              </div>
            </div>
          </div>
        </footer>
      </div>
    </div>
  );
}

export default App;
